terraform_example.snippet:
resource "aws_wafv2_web_acl" "method_enforcement" {
  name  = "method-enforcement-baseline"
  scope = "REGIONAL"

  default_action {
    allow {}
  }

  rule {
    name     = "block-high-risk-methods"
    priority = 10

    # rollout: start in count {}, then switch to block {}
    action {
      count {}
    }

    statement {
      or_statement {
        statement {
          byte_match_statement {
            search_string         = "TRACE"
            positional_constraint = "EXACTLY"
            field_to_match { method {} }
            text_transformation { priority = 0 type = "NONE" }
          }
        }
        statement {
          byte_match_statement {
            search_string         = "TRACK"
            positional_constraint = "EXACTLY"
            field_to_match { method {} }
            text_transformation { priority = 0 type = "NONE" }
          }
        }
        statement {
          byte_match_statement {
            search_string         = "CONNECT"
            positional_constraint = "EXACTLY"
            field_to_match { method {} }
            text_transformation { priority = 0 type = "NONE" }
          }
        }
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "blockHighRiskMethods"
      sampled_requests_enabled   = true
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "methodEnforcementBaseline"
    sampled_requests_enabled   = true
  }
}
